const input = $input.all()[0].json;

// Validar campos obrigatórios
if (!input.nome_empresa || !input.whatsapp || !input.categoria) {
  throw new Error('Campos obrigatórios faltando: nome_empresa, whatsapp, categoria');
}

// LIMPAR WHATSAPP
let whatsapp = input.whatsapp.toString().replace(/\D/g, '');

if (whatsapp.length < 10) {
  throw new Error(`WhatsApp inválido: ${input.whatsapp}`);
}

if (!whatsapp.startsWith('55')) {
  whatsapp = '55' + whatsapp;
}

if (whatsapp.length < 12 || whatsapp.length > 13) {
  throw new Error(`WhatsApp inválido: ${whatsapp}`);
}

// CRIAR SLUG ÚNICO
const slugBase = input.nome_empresa
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9\s]/g, '')
  .replace(/\s+/g, '-')
  .substring(0, 50);

const timestamp = Date.now();
const slug = `${slugBase}-${timestamp}`;

// EXTRAIR CIDADE E BAIRRO
let cidade = input.cidade_bairro || '';
let bairro = '';

if (input.cidade_bairro && input.cidade_bairro.includes(' - ')) {
  const partes = input.cidade_bairro.split(' - ');
  cidade = partes[0].trim();
  bairro = partes[1].trim();
}

return {
  nome_empresa: input.nome_empresa.trim(),
  whatsapp_limpo: whatsapp,
  categoria: input.categoria.trim(),
  cidade: cidade,
  bairro: bairro,
  cidade_bairro: input.cidade_bairro || cidade,
  slug: slug,
  origem: input.origem || 'manual'
};"},"id":"a26a9b20-89ee-4726-820d-99adb2496c37","name":"Code - Validar e Preparar","type":"n8n-nodes-base.code","typeVersion":2,"position":[6960,-3200]},{"parameters":{"operation":"executeQuery","query":"INSERT INTO leads_prospeccao (
