// Parsear histórico existente
let historico = [];
try {
  historico = typeof lead.historico_conversa === 'string' ? 
    JSON.parse(lead.historico_conversa) : 
    (lead.historico_conversa || []);
} catch (e) {
  historico = [];
}

// Adicionar nova mensagem ao histórico
historico.push({
  role: 'cliente',
  content: novaMensagem,
  timestamp: new Date().toISOString()
});

// Verificar se é PRIMEIRA resposta (enviar site demo)
const ehPrimeiraResposta = !lead.cliente_respondeu;

// Calcular score de interesse baseado em palavras-chave
let scoreInteresse = lead.score_interesse || 0;
const palavrasPositivas = ['sim', 'quero', 'interessado', 'quanto', 'preço', 'custo', 'aceito', 'pode'];
const palavrasNegativas = ['não', 'depois', 'talvez', 'pensar', 'caro'];

const mensagemLower = novaMensagem.toLowerCase();
palavrasPositivas.forEach(palavra => {
  if (mensagemLower.includes(palavra)) scoreInteresse += 10;
});
palavrasNegativas.forEach(palavra => {
  if (mensagemLower.includes(palavra)) scoreInteresse -= 5;
});

scoreInteresse = Math.max(0, Math.min(100, scoreInteresse));

return {
  lead_id: lead.id,
  nome_empresa: lead.nome_empresa,
  site_demo_url: lead.site_demo_url,
  fase_venda: lead.fase_venda,
  eh_primeira_resposta: ehPrimeiraResposta,
  historico_conversa: historico,
  nova_mensagem: novaMensagem,
  score_interesse: scoreInteresse,
  whatsapp: lead.whatsapp
};"},"id":"d19c4593-a1ee-45f2-9f52-4222978f10c0","name":"Code - Preparar Contexto","type":"n8n-nodes-base.code","typeVersion":2,"position":[7504,-2176]},{"parameters":{"conditions":{"boolean":[{"value1":"={{ $json.eh_primeira_resposta }}","operation":"equal","value2":true}]},"options":{}},"id":"318ded76-ca2b-41a1-8f28-f6695d4071d9","name":"IF - Primeira Resposta?","type":"n8n-nodes-base.if","typeVersion":2,"position":[7712,-2176]},{"parameters":{"jsCode":"// Mensagem com site demo + pitch
